function normalizeVanguardSummary(payload: unknown): VanguardSummary {
  const data = unwrapObject(payload);
  const distributorCode =
    stringValue(data.distributor_code || data.distributorCode) || "--";
  return {
    distributorName: stringValue(data.distributor_name || data.distributorName),
    distributorCode,
    distributorUrl:
      stringValue(data.distributor_url || data.distributorUrl) ||
      getDistributorInviteUrl(distributorCode),
    historicalRevenueShare: numberValue(
      data.revenue_share_all_time || data.revenueShareAllTime
    ),
    brokerTier: normalizeTierLabel(data.tier),
    canAssignMinTier: Boolean(
      data.tier_assignment_privilege || data.tierAssignmentPrivilege
    ),
  };
}

function normalizeInviteeRow(row: Record<string, unknown>): Invitee {
  const brokerId = stringValue(row.broker_id || row.brokerId);
  return {
    address:
      stringValue(row.address || row.invitee_address || row.inviteeAddress) ||
      "--",
    brokerId,
    brokerName: stringValue(row.broker_name || row.brokerName),
    tier: normalizeTierLabel(row.tier),
    minTier: normalizeOptionalTierLabel(row.min_tier || row.minTier),
    volume30d: formatCurrency(
      numberValue(row.volume_last30_days || row.volumeLast30Days || row.volume)
    ),
    joined: stringValue(row.created_time || row.createdTime || row.joined),
    status: stringValue(row.status),
  };
}

function normalizeRevenueShareRow(
  row: Record<string, unknown>
): RevenueShareRow {
  const revenueShareId = stringValue(
    row.revenue_share_id || row.revenueShareId || row.id
  );
  return {
    id:
      revenueShareId ||
      stringValue(row.distribution_time || row.distributionTime),
    distributionTime: formatApiTime(
      row.distribution_time || row.distributionTime
    ),
    totalRevenueShare: formatCurrencyFixed(
      numberValue(row.total_revenue_share || row.totalRevenueShare),
      2
    ),
    totalInviteeVolume: formatCurrency(
      numberValue(row.total_invitee_volume || row.totalInviteeVolume)
    ),
    builderTier: normalizeTierLabel(row.tier),
    revenueShareId,
    periodStart: formatApiTime(
      row.revenue_share_start_time || row.revenueShareStartTime
    ),
    periodEnd: formatApiTime(
      row.revenue_share_end_time || row.revenueShareEndTime
    ),
  };
}

function normalizeRevenueShareDetailRow(
  row: Record<string, unknown>
): RevenueShareDetailRecord {
  const takerVolume = numberValue(
    row.invitee_taker_volume || row.inviteeTakerVolume
  );
  const makerVolume = numberValue(
    row.invitee_maker_volume || row.inviteeMakerVolume
  );
  return {
    inviteeAddress:
      stringValue(row.address || row.invitee_address || row.inviteeAddress) ||
      "--",
    brokerId: stringValue(row.broker_id || row.brokerId),
    brokerName: stringValue(row.broker_name || row.brokerName),
    myRevenueShare: numberValue(
      row.revenue_share || row.revenueShare || row.myRevenueShare
    ),
    inviteeVolume:
      takerVolume + makerVolume ||
      numberValue(row.invitee_volume || row.inviteeVolume),
    inviteeTakerVolume: takerVolume,
    inviteeMakerVolume: makerVolume,
    inviteeBrokerTier: normalizeTierLabel(row.tier || row.inviteeBrokerTier),
  };
}

function getVolumeTier(totalVolume: number): TierKey {
  if (totalVolume >= 1_000_000_000) return "diamond";
  if (totalVolume >= 100_000_000) return "platinum";
  if (totalVolume >= 10_000_000) return "gold";
  if (totalVolume >= 1_000_000) return "silver";
  return "public";
}

