function BuilderDistributorEligibilityGate({
  profile,
}: {
  profile: Profile | null;
}) {
  const builderName = profile?.builderName || "Your DEX";
  const builderOnboardingDone = Boolean(
    profile?.builderName &&
      profile?.pathway &&
      (profile.dexConfigured || profile.brokerId)
  );
  const graduated = !!profile?.graduated;
  const adminReady = profile?.adminRegistered === true;
  const ctaHref =
    !builderOnboardingDone || !graduated ? "/home" : "/admin-setup";
  const ctaLabel = !builderOnboardingDone
    ? "Complete builder onboarding"
    : !graduated
      ? "Continue to graduation"
      : "Finish admin setup";
  const steps = [
    {
      title: "Complete builder onboarding",
      description:
        "Finish the builder setup tasks in Home before joining as a distributor.",
      done: builderOnboardingDone,
    },
    {
      title: "Graduate your DEX",
      description:
        "Builder-path distributors become eligible only after their DEX has graduated.",
      done: graduated,
    },
    {
      title: "Finish admin setup",
      description:
        "A graduated builder needs admin access before distributor management is available.",
      done: adminReady,
    },
  ];

  return (
    <section className="rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-4 sm:p-6 shadow-[var(--shadow-card)]">
      <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
        <div>
          <p className="text-sm font-medium text-(--fg-brand)">
            Builder distributor path
          </p>
          <h1 className="mt-2 text-2xl font-semibold text-(--fg-primary)">
            Graduate before joining the distributor program
          </h1>
          <p className="mt-3 max-w-2xl text-sm leading-6 text-(--fg-secondary)">
            {builderName} is a builder profile. Complete builder onboarding and
            graduation first, then return here to manage the distributor
            program.
          </p>
        </div>
        <LocalizedLink
          to={ctaHref}
          className="inline-flex shrink-0 items-center justify-center gap-2 rounded-full px-5 py-3 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
          style={{ background: "var(--bg-brand-grad)" }}
        >
          {ctaLabel}
          <ArrowRight className="h-4 w-4" />
        </LocalizedLink>
      </div>

      <div className="grid gap-3">
        {steps.map((step, index) => (
          <div
            key={step.title}
            className="flex items-start gap-3 rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-4"
          >
            <div
              className={`flex h-8 w-8 shrink-0 items-center justify-center rounded-full ${step.done ? "bg-[rgba(29,246,181,0.14)] text-[#1DF6B5]" : "bg-(--bg-hover) text-(--fg-secondary)"}`}
            >
              {step.done ? (
                <Check className="h-4 w-4" />
              ) : (
                <span className="text-sm font-medium">{index + 1}</span>
              )}
            </div>
            <div>
              <div className="text-sm font-medium text-(--fg-primary)">
                {step.title}
              </div>
              <p className="mt-1 text-sm leading-5 text-(--fg-secondary)">
                {step.description}
              </p>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}

export default function DistributorProgramPage() {
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const pageTitle = "Orderly distributor program";

  useEffect(() => {
    let cancelled = false;
    const storedProfile = getProfile();
    setProfile(storedProfile);

    if (
      !storedProfile ||
      storedProfile.role === "ambassador" ||
      storedProfile.role === "broker"
    ) {
      setLoading(false);
      return () => {
        cancelled = true;
      };
    }

    fetchDexCreatorDexStatus()
      .then(status => {
        if (cancelled || !status || status.exists === false) return;
        const currentProfile = getProfile() || storedProfile;
        const hasGraduatedBrokerId = Boolean(
          status.brokerId && status.brokerId !== "demo"
        );
        const nextProfile: Profile = {
          ...currentProfile,
          brokerId: status.brokerId || currentProfile.brokerId,
          builderName: status.brokerName || currentProfile.builderName,
          dexConfigured: true,
          pathway:
            status.integrationType === "low_code"
              ? "low-code"
              : status.integrationType === "custom"
                ? "sdk"
                : currentProfile.pathway,
          graduated: hasGraduatedBrokerId,
          adminRegistered: hasGraduatedBrokerId && status.isGraduated === true,
        };
        saveProfile(nextProfile);
        setProfile(nextProfile);
        window.dispatchEvent(new CustomEvent("profileUpdated"));
      })
      .catch(() => {
        // Keep local status if dex-creator is unavailable.
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, []);

  const isDistributor =
    profile?.role === "ambassador" || profile?.role === "broker";
  const isBuilderProfile = !!profile && !isDistributor;
  const isBuilderReadyForDistributor =
    isBuilderProfile && !!profile.graduated && profile.adminRegistered === true;
  const managementProfile = isDistributor
    ? profile
    : isBuilderReadyForDistributor
      ? ({ ...profile, role: "broker" } as Profile)
      : null;

  function promoteToDistributor() {
    const p = getProfile();
    if (!p) return;
    const alreadyDistributor = p.role === "ambassador" || p.role === "broker";
    const readyForDistributor =
      (!!p.graduated || Boolean(p.brokerId && p.brokerId !== "demo")) &&
      p.adminRegistered === true;
    if (!alreadyDistributor && !readyForDistributor) {
      toast({
        title:
          "Complete builder onboarding and graduation before applying for the distributor program.",
        variant: "destructive",
      });
      return;
    }
    if (!alreadyDistributor) p.role = "broker";
    saveProfile(p);
    setProfile(p);
    window.dispatchEvent(new CustomEvent("profileUpdated"));
  }

  if (loading) {
    return (
      <PageShell pageTitle={pageTitle}>
        <div className="flex min-h-[400px] items-center justify-center">
          <div className="inline-block h-8 w-8 animate-spin rounded-full border-2 border-(--line-subtle) border-t-(--fg-brand)" />
        </div>
      </PageShell>
    );
  }

  if (managementProfile) {
    return (
      <PageShell pageTitle={pageTitle}>
        <DistributorManagementPanel
          profile={managementProfile}
          onProfileChange={setProfile}
        />
      </PageShell>
    );
  }

  if (isBuilderProfile) {
    return (
      <PageShell pageTitle={pageTitle}>
        <BuilderDistributorEligibilityGate profile={profile} />
      </PageShell>
    );
  }

  return (
    <PageShell pageTitle={pageTitle}>
      <PublicDistributorPage onApply={promoteToDistributor} />
    </PageShell>
  );
}

