function isDistributorMockMode() {
  if (typeof window === "undefined") return false;
  const params = new URLSearchParams(window.location.search);
  return (
    params.get("mock") === "1" || params.get("mockDistributorData") === "true"
  );
}

function getSupportedWithdrawChainIds() {
  return getOrderlyEnvConfig().env === "prod"
    ? [1, 42161, 8453]
    : [11155111, 421614, 84532];
}

function getWithdrawChainName(chainId: number) {
  const names: Record<number, string> = {
    1: "Ethereum",
    42161: "Arbitrum",
    8453: "Base",
    11155111: "Sepolia",
    421614: "Arbitrum Sepolia",
    84532: "Base Sepolia",
  };
  return names[chainId] || `Chain ${chainId}`;
}

async function fetchWithdrawChains() {
  const payload = await apiClient<{
    success?: boolean;
    message?: string;
    data?: { rows?: TokenInfoRow[] };
    rows?: TokenInfoRow[];
  }>({
    endpoint: "/v1/public/token",
    token: null,
    showToastOnError: false,
  });
  if (!payload?.success)
    throw new Error(payload?.message || "Failed to load withdrawal networks.");
  const rows = payload.data?.rows || payload.rows || [];
  const usdc = Array.isArray(rows)
    ? rows.find((row: TokenInfoRow) => row.token === "USDC")
    : null;
  const supported = new Set(getSupportedWithdrawChainIds());
  return (usdc?.chain_details || [])
    .map(
      (
        detail: NonNullable<TokenInfoRow["chain_details"]>[number]
      ): WithdrawChain | null => {
        const chainId = Number(detail.chain_id);
        if (!supported.has(chainId)) return null;
        return {
          chainId,
          name: getWithdrawChainName(chainId),
          withdrawalFee: Number(detail.withdrawal_fee || 0),
          minimumWithdrawAmount: Number(usdc?.minimum_withdraw_amount || 0),
          decimals: detail.decimals || 6,
        };
      }
    )
    .filter((chain): chain is WithdrawChain => chain !== null);
}

function formatInputAmount(value: number) {
  if (!Number.isFinite(value) || value <= 0) return "0";
  return value.toFixed(8).replace(/\.?0+$/, "");
}

function getUsdcHolding(holdings: HoldingRow[]) {
  return holdings.find(row => row.token === "USDC") || null;
}

function normalizeWithdrawalHistoryRow(
  row: Record<string, unknown>
): WithdrawalHistoryRecord {
  const chainId = row.chain_id ?? row.chainId;
  return {
    id: stringValue(row.id || row.withdraw_id || row.request_id) || "--",
    txId: stringValue(row.tx_id || row.txId || row.transaction_id),
    side: stringValue(row.side) || "WITHDRAW",
    token: stringValue(row.token || row.asset || row.symbol) || "USDC",
    amount: numberValue(row.amount),
    fee: numberValue(row.fee),
    status: stringValue(row.trans_status || row.status || row.state) || "--",
    createdTime: formatApiTime(row.created_time || row.createdTime),
    updatedTime: formatApiTime(row.updated_time || row.updatedTime),
    chainId:
      chainId === null || chainId === undefined || chainId === ""
        ? "--"
        : String(chainId),
  };
}

