function truncateIdentifier(value: string, start: number, end: number) {
  return value.length > start + end + 3
    ? `${value.slice(0, start)}...${value.slice(-end)}`
    : value;
}

function CopyableIdentifier({
  value,
  start = 10,
  end = 6,
}: {
  value: string;
  start?: number;
  end?: number;
}) {
  const [copied, setCopied] = useState(false);
  if (!value || value === "--") return <span>--</span>;
  const displayValue = truncateIdentifier(value, start, end);

  async function copyValue() {
    try {
      await navigator.clipboard.writeText(value);
      setCopied(true);
      window.setTimeout(() => setCopied(false), 1400);
    } catch {
      setCopied(false);
    }
  }

  return (
    <span className="inline-flex max-w-full items-center gap-1.5">
      <span className="truncate" title={value}>
        {displayValue}
      </span>
      <button
        type="button"
        onClick={copyValue}
        aria-label={copied ? "Copied" : "Copy"}
        className={`inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-md transition-colors ${copied ? "text-[#1DF6B5]" : "text-(--fg-tertiary) hover:bg-(--bg-hover) hover:text-(--fg-primary)"}`}
      >
        {copied ? (
          <Check className="h-3.5 w-3.5" />
        ) : (
          <Copy className="h-3.5 w-3.5" />
        )}
      </button>
    </span>
  );
}

function TxIdentifierLink({
  txId,
  chainId,
}: {
  txId: string;
  chainId: string;
}) {
  const [copied, setCopied] = useState(false);
  const explorerUrl = getExplorerTxUrl(chainId, txId);
  if (!txId) return <span>--</span>;

  async function copyValue() {
    try {
      await navigator.clipboard.writeText(txId);
      setCopied(true);
      window.setTimeout(() => setCopied(false), 1400);
    } catch {
      setCopied(false);
    }
  }

  return (
    <span className="inline-flex max-w-full items-center gap-1.5">
      {explorerUrl ? (
        <a
          href={explorerUrl}
          target="_blank"
          rel="noreferrer"
          className="inline-flex min-w-0 items-center gap-1 text-(--fg-secondary) transition-colors hover:text-(--fg-primary) hover:underline"
          title={txId}
        >
          <span className="truncate">{truncateIdentifier(txId, 8, 6)}</span>
          <ExternalLink className="h-3.5 w-3.5 shrink-0" />
        </a>
      ) : (
        <span className="truncate" title={txId}>
          {truncateIdentifier(txId, 8, 6)}
        </span>
      )}
      <button
        type="button"
        onClick={copyValue}
        aria-label={copied ? "Copied" : "Copy"}
        className={`inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-md transition-colors ${copied ? "text-[#1DF6B5]" : "text-(--fg-tertiary) hover:bg-(--bg-hover) hover:text-(--fg-primary)"}`}
      >
        {copied ? (
          <Check className="h-3.5 w-3.5" />
        ) : (
          <Copy className="h-3.5 w-3.5" />
        )}
      </button>
    </span>
  );
}

