function HeaderWithTooltip({
  label,
  tooltip,
}: {
  label: string;
  tooltip: string;
}) {
  const iconRef = useRef<HTMLSpanElement>(null);
  const [position, setPosition] = useState<{
    top: number;
    left: number;
  } | null>(null);

  function showTooltip() {
    const rect = iconRef.current?.getBoundingClientRect();
    if (!rect) return;
    setPosition({
      top: rect.bottom + 8,
      left: Math.min(rect.left + rect.width / 2, window.innerWidth - 140),
    });
  }

  return (
    <span className="inline-flex items-center gap-1.5">
      <span>{label}</span>
      <span
        ref={iconRef}
        className="inline-flex"
        onMouseEnter={showTooltip}
        onMouseLeave={() => setPosition(null)}
        onFocus={showTooltip}
        onBlur={() => setPosition(null)}
      >
        <Info className="h-3.5 w-3.5 cursor-help text-(--fg-tertiary)" />
      </span>
      {position && (
        <span
          className="pointer-events-none fixed z-300 w-64 -translate-x-1/2 whitespace-normal rounded-lg border border-(--line-subtle) bg-(--bg-popout) p-2 text-left text-xs font-normal leading-5 text-(--fg-secondary) shadow-xl"
          style={{ top: position.top, left: position.left }}
        >
          {tooltip}
        </span>
      )}
    </span>
  );
}

