function DistributorWithdrawModal({
  open,
  onClose,
  onWithdraw,
  walletAddress,
  availableBalance,
  chains,
  loadingChains,
  submitting,
  error,
  currentChainId,
}: {
  open: boolean;
  onClose: () => void;
  onWithdraw: (
    amount: string,
    chain?: WithdrawChain | null
  ) => void | Promise<void>;
  walletAddress?: string;
  availableBalance: number;
  chains: WithdrawChain[];
  loadingChains: boolean;
  submitting: boolean;
  error?: string;
  currentChainId?: number;
}) {
  const { t } = useTranslation();
  const [amount, setAmount] = useState("");
  const [selectedChainId, setSelectedChainId] = useState<number | null>(null);
  const selectedChain =
    chains.find(chain => chain.chainId === selectedChainId) || null;
  const amountNumber = Number(amount.replace(/,/g, ""));
  const hasAmount = amount.trim().length > 0;
  const minimumGrossAmount = selectedChain
    ? selectedChain.minimumWithdrawAmount + selectedChain.withdrawalFee
    : 0;
  const estimatedReceived =
    selectedChain && Number.isFinite(amountNumber) && amountNumber > 0
      ? Math.max(amountNumber - selectedChain.withdrawalFee, 0)
      : 0;
  const validationError =
    hasAmount && (!Number.isFinite(amountNumber) || amountNumber <= 0)
      ? "Enter a valid withdrawal amount."
      : hasAmount && amountNumber > availableBalance
        ? `Insufficient balance. Available: ${formatTokenAmount(availableBalance)} USDC`
        : hasAmount && selectedChain && amountNumber < minimumGrossAmount
          ? `Minimum withdrawal is ${formatTokenAmount(minimumGrossAmount)} USDC including network fee.`
          : "";
  const displayedError = validationError || error || "";
  const submitDisabled =
    submitting ||
    loadingChains ||
    !hasAmount ||
    !selectedChain ||
    Boolean(validationError);

  useEffect(() => {
    if (!open) return;
    setAmount("");
    const matchingChain = chains.find(
      chain => chain.chainId === currentChainId
    );
    setSelectedChainId((matchingChain || chains[0])?.chainId || null);
  }, [chains, currentChainId, open]);

  return (
    <Modal
      open={open}
      onClose={submitting ? () => {} : onClose}
      title="Withdraw distributor balance"
    >
      <div className="space-y-5">
        <div className="space-y-2">
          <div className="flex items-center rounded-lg border border-(--line-subtle) bg-(--bg-input) px-4 py-3">
            <input
              type="text"
              inputMode="decimal"
              value={amount}
              onChange={event => {
                const nextValue = event.target.value;
                if (nextValue === "" || /^\d*\.?\d*$/.test(nextValue))
                  setAmount(nextValue);
              }}
              placeholder="Quantity"
              className="flex-1 bg-transparent text-sm text-(--fg-primary) outline-none placeholder:text-(--fg-placeholder)"
            />
            <span className="text-sm font-semibold text-(--fg-primary)">
              USDC
            </span>
          </div>
          <div className="flex items-center justify-between text-xs">
            <span className="text-(--fg-secondary)">
              Available:{" "}
              <span className="font-medium">
                {formatTokenAmount(availableBalance)} USDC
              </span>
            </span>
            <button
              type="button"
              onClick={() => setAmount(formatInputAmount(availableBalance))}
              className="font-medium text-(--fg-brand) hover:opacity-80"
            >
              Max
            </button>
          </div>
        </div>

        <div className="border-t border-(--line-subtle)" />

        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <span className="text-xs text-(--fg-secondary)">
              Destination wallet
            </span>
            <div className="flex items-center gap-2">
              <Wallet className="h-3.5 w-3.5 text-(--fg-secondary)" />
              <code className="text-xs font-medium text-(--fg-primary)">
                {walletAddress ? formatAddress(walletAddress) : "Not connected"}
              </code>
            </div>
          </div>

          <div className="flex items-center justify-between gap-4">
            <span className="text-xs text-(--fg-secondary)">Network</span>
            <Select
              value={selectedChainId ? String(selectedChainId) : ""}
              onValueChange={value => setSelectedChainId(Number(value))}
              disabled={loadingChains || chains.length === 0}
            >
              <SelectTrigger className="h-8 w-full sm:w-48 border-(--line-subtle) bg-(--bg-surface-secondary) text-xs text-(--fg-primary) hover:bg-(--bg-hover)">
                <SelectValue
                  placeholder={
                    loadingChains ? "Loading networks..." : "Select network"
                  }
                />
              </SelectTrigger>
              <SelectContent className="z-200 border-(--line-subtle) bg-(--bg-popout) text-(--fg-primary)">
                {chains.map(chain => (
                  <SelectItem
                    key={chain.chainId}
                    value={String(chain.chainId)}
                    className="focus:bg-(--bg-hover) focus:text-(--fg-primary)"
                  >
                    <span className="flex items-center gap-2">
                      <Globe className="h-3.5 w-3.5 text-(--fg-secondary)" />
                      <span>{chain.name}</span>
                    </span>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="flex items-center justify-between">
            <span className="text-xs text-(--fg-secondary)">Fee</span>
            <span className="text-xs font-medium text-(--fg-secondary)">
              {formatTokenAmount(selectedChain?.withdrawalFee || 0)} USDC
            </span>
          </div>
          <div className="flex items-center justify-between">
            <span className="text-xs text-(--fg-secondary)">Minimum</span>
            <span className="text-xs font-medium text-(--fg-secondary)">
              {formatTokenAmount(minimumGrossAmount)} USDC
            </span>
          </div>
          <div className="flex items-center justify-between">
            <span className="text-xs text-(--fg-secondary)">
              Estimated received
            </span>
            <span className="text-xs font-medium text-(--fg-primary)">
              {formatTokenAmount(estimatedReceived)} USDC
            </span>
          </div>
        </div>

        {displayedError && (
          <div className="rounded-lg border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.08)] px-3 py-2 text-xs text-[#FF6390]">
            {displayedError}
          </div>
        )}

        <div className="rounded-lg border border-[rgba(72,189,255,0.25)] bg-[rgba(72,189,255,0.08)] p-3">
          <div className="flex items-start gap-2 text-xs leading-5 text-(--fg-secondary)">
            <Info className="mt-0.5 h-3.5 w-3.5 shrink-0 text-[#48BDFF]" />
            Orderly will ask your connected wallet to sign the withdrawal
            request. Funds are sent to the same wallet address.
          </div>
        </div>

        <div className="flex gap-3">
          <button
            type="button"
            onClick={onClose}
            disabled={submitting}
            className="flex-1 rounded-full border border-(--line-subtle) bg-transparent px-4 py-2.5 text-sm font-medium text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary) disabled:cursor-not-allowed disabled:opacity-50"
          >
            {t("common.cancel")}
          </button>
          <button
            type="button"
            onClick={() => onWithdraw(amount, selectedChain)}
            disabled={submitDisabled}
            className="flex-1 rounded-full px-4 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
            style={{ background: "var(--bg-brand-grad)" }}
          >
            {submitting ? t("common.submitting") : t("common.withdraw")}
          </button>
        </div>
      </div>
    </Modal>
  );
}

